import{_ as d,c as o,o as r,ag as e}from"./chunks/framework.Ds6Eueu6.js";const a="/assets/01-is-vs-oos-scatter-and-top20.DK3igHh4.png",n="/assets/02-walk-forward-rolling-vs-anchored.CJPYDu6z.png",l="/assets/03-cross-validation-5fold.Ye26MQ47.png",s="/assets/04-rule-burden-4a-4b.DuHicT9Q.png",m=JSON.parse('{"title":"第六章：看清好看的回测：别被自己骗了","description":"","frontmatter":{},"headers":[],"relativePath":"book/q6-avoid-overfitting.md","filePath":"book/q6-avoid-overfitting.md","lastUpdated":null}'),p={name:"book/q6-avoid-overfitting.md"};function i(c,t,h,g,u,b){return r(),o("div",null,t[0]||(t[0]=[e('<h1 id="第六章-看清好看的回测-别被自己骗了" tabindex="-1">第六章：看清好看的回测：别被自己骗了 <a class="header-anchor" href="#第六章-看清好看的回测-别被自己骗了" aria-label="Permalink to &quot;第六章：看清好看的回测：别被自己骗了&quot;">​</a></h1><p>第五章我们给策略做了一次全面体检——基准对比、逐年拆解、收益分布、参数敏感性。现在手上有一套完整的评估方法论。</p><p>但所有体检结果都基于一个前提：<strong>回测结果是真实的。</strong></p><p>真的吗？</p><p>回顾第五章的发现：TopNRanking 策略在 2021 年亏了 10%，换遍所有动量窗口都救不回来——这是动量策略的结构性弱点。但同样的策略在 2023-2025 的好市场上表现不错。这引出一个危险的念头：<strong>如果我们在好市场上精心挑选参数，找到“收益最好”的组合，信心满满地投入资金——未来再遇到差市场会怎么样？</strong></p><p>回测可以调参数让收益翻倍——这是真的好，还是自欺欺人？</p><h3 id="路线图" tabindex="-1">路线图 <a class="header-anchor" href="#路线图" aria-label="Permalink to &quot;路线图&quot;">​</a></h3><p><strong>选什么标的（第二章）→ 每个买多少（第三章）→ 什么时候买卖（第四章）→ 怎么验证有效（第五章）→ 如何避免自欺欺人（第六章）</strong></p><p><strong>这一章你仍在飞轮的“归因层”，但主练动作切到了“疑”——本书口号“做要规则、看要指标、还要怀疑你的指标”中“还要怀疑你的指标”，就是这一章要让你练成肌肉记忆的事。</strong> 第一章你已经亲手撞过一次墙——参数扫描里“冠军”在样本外掉到水下；这一章我们给你<strong>四把铲子</strong>，让那种墙以后看见就能挖开：样本内/外、Walk-forward、交叉验证、规则负担。本章解决第五步——识别过拟合陷阱，学会检验策略的真实有效性。四步对应的问题与方法如表 6-1 所示。</p><p><strong>表 6-1 第六章四节问题与方法对照</strong></p><table tabindex="0"><thead><tr><th>步骤</th><th>问题</th><th>方法</th></tr></thead><tbody><tr><td>Step 1</td><td>能不能找到收益最好的参数？</td><td>参数优化 + 样本内/样本外</td></tr><tr><td>Step 2</td><td>市场在变，参数也该跟着变吧？</td><td>Walk-forward 分析</td></tr><tr><td>Step 3</td><td>一条路径够可靠吗？</td><td>交叉验证</td></tr><tr><td>Step 4</td><td>规则越多回测越好——是好事吗？</td><td>规则负担</td></tr></tbody></table><p>铁律不变：<strong>先猜后验，数据说了算。</strong></p><p>（操作流程见前言“怎么使用这本书”。）</p><hr><h2 id="_6-1-能不能找到收益最好的参数" tabindex="-1">6.1 能不能找到收益最好的参数？ <a class="header-anchor" href="#_6-1-能不能找到收益最好的参数" aria-label="Permalink to &quot;6.1 能不能找到收益最好的参数？&quot;">​</a></h2><p><strong>和第一章 1.5 节的关系：</strong> 第一章末尾你扫过 24 个一维参数（均线窗口），用 60-40 切分做样本外测试，已经撞过一次过拟合的墙。这一章接着上一次的脚印继续走——<strong>同一种切法，但量级跃迁</strong>：参数从 1 维涨到 4 维（动量 / 波动 / 调仓 / 止损），组合数从 24 涨到 490。维度多了之后，过拟合的样子会变什么样？这一节给你答案。</p><p>第五章用了默认参数——动量窗口 20 天、波动率窗口 20 天、调仓频率 10 天。但这些是随便选的，不是天经地义的。</p><p>直觉告诉我们：<strong>多试几组参数，选收益最高的就行了。</strong> 几百种组合里总有比默认值更好的吧？</p><p>这个想法太自然了。就像买手机——把市面上所有型号的参数列出来，逐项比较，选评分最高的那款。参数也一样，把所有组合都试一遍，选出表现最好的——这叫<strong>参数优化</strong>，也叫<strong>网格搜索（Grid Search）</strong>——一个参数组合就像是一个格子，挨个格子试一遍，总能找到最优解。</p><p>真的这么简单吗？试试看。</p><h3 id="动手实验-1-参数优化与样本内-样本外" tabindex="-1">动手实验 1：参数优化与样本内/样本外 <a class="header-anchor" href="#动手实验-1-参数优化与样本内-样本外" aria-label="Permalink to &quot;动手实验 1：参数优化与样本内/样本外&quot;">​</a></h3><p>这个实验用到 open-xquant 的参数优化工具：<code>GridSearch</code>（网格搜索——把所有参数组合都试一遍）和 <code>WalkForward</code>（前推分析——模拟“边走边调”的真实场景）。</p><p>我们一起把这份 spec 写出来。这次重点看三件新东西：<strong>维度跃迁</strong>（从一维到四维参数）、<strong>时段语义切分</strong>（好市场挑参数 / 差市场验证）、<strong>业务约束的可读字符串写法</strong>。</p><h4 id="起草上下文-任务" tabindex="-1">起草上下文 + 任务 <a class="header-anchor" href="#起草上下文-任务" aria-label="Permalink to &quot;起草上下文 + 任务&quot;">​</a></h4><p>第一章 1.5 节用一行“前 60% / 后 40%”切了一刀——这是结构性切分。这一节不一样：每段时间要带金融含义。</p><blockquote><p><strong>上下文</strong>：本章探讨参数优化和过拟合。第五章看了默认参数（动量 20 / 波动率 20 / 调仓 10）的 plateau vs peak，但学员从没试过“从一堆参数里找最好的”。承接第五章的叙事——TopNRanking 在 2017-2020 好市场上参数选得好，2021 年差市场会怎么样？</p><p><strong>任务</strong>：在 <code>q6-avoid-overfitting.ipynb</code> 用 <code>oxq.optimize.GridSearch</code> 跑参数网格搜索，用样本内 / 样本外方法检验过拟合。</p></blockquote><blockquote><p>📌 <strong>要点</strong>：数据切分要带“市场含义”。第一章的 60/40 是按比例切的，这里换成“2017-2020 好市场 / 2021-2023 差市场”——后者把每段对应的市场行情说清楚，学员才能看懂“为什么是这两段”。<strong>任何切分型 spec，起止日期都要四个全锁死（IS_START / IS_END / OOS_START / OOS_END），否则今年跑、明年跑切出来不一样，过拟合证据就站不住。</strong></p></blockquote><h4 id="起草要求-维度跃迁与业务约束" tabindex="-1">起草要求：维度跃迁与业务约束 <a class="header-anchor" href="#起草要求-维度跃迁与业务约束" aria-label="Permalink to &quot;起草要求：维度跃迁与业务约束&quot;">​</a></h4><p>第一章扫过 24 个一维参数（均线窗口）。这一节直接跳到 4 维——动量 / 波动率 / 调仓频率 / 止损阈值。</p><blockquote><p><strong>要求</strong>：</p><ol><li>数据切割：样本内 <code>2017-01-01 ~ 2020-12-31</code>、样本外 <code>2021-01-01 ~ 2023-01-31</code>，四个端点全锁死</li><li>用 <code>ParameterSet</code> 定义参数空间：动量 / 波动率窗口 <code>[10, 15, 20, 25, 30]</code>、调仓频率 <code>[5, 10, 15, 21]</code>、止损阈值 <code>[0.03, 0.05, 0.07, 0.10, 0.15, 0.20]</code></li><li>分两组跑：无止损组（3 维）+ 含止损组（4 维），约束后总组合数约 490</li><li>业务约束用可读字符串写：<code>add_constraint(&quot;RebalanceFrequencyRule.interval_days &lt;= mom.period&quot;)</code>、<code>&lt;= vol.period</code></li><li>调仓频率不应超过信号窗口——这是领域知识，不是技术约束</li><li>用 <code>GridSearch</code> 跑两组参数空间，在样本内、样本外各跑一次</li></ol></blockquote><blockquote><p>📌 <strong>要点</strong>：维度跃迁后要分组管理。一维扫描随便扫，四维直接扫会爆——5×5×4×6 = 600 还要约束过滤。<strong>分两组跑（无止损 70 组合 + 含止损 420 组合）既能控制总数，又能让止损这一维在结果里被单独看清——也为后面“规则负担”那一节埋了伏笔。</strong></p></blockquote><blockquote><p>📌 <strong>要点</strong>：业务约束用可读字符串，不要用 lambda。<code>&quot;RebalanceFrequencyRule.interval_days &lt;= mom.period&quot;</code> 这种 DSL 字符串比 <code>lambda p: p[&quot;RebalanceFrequencyRule.interval_days&quot;] &lt;= p[&quot;mom.period&quot;]</code> 更适合 0 基础学员看。<strong>约束的“为什么”要写到 spec 注释里——“信号 20 天更新一次，调仓 60 天才看一次 = 在用过期信号做决策”——这是把领域知识嵌入 spec 的标准写法。</strong></p></blockquote><h4 id="起草结果呈现" tabindex="-1">起草结果呈现 <a class="header-anchor" href="#起草结果呈现" aria-label="Permalink to &quot;起草结果呈现&quot;">​</a></h4><blockquote><p><strong>结果呈现</strong>：</p><ol><li>打印 Top 20 表（按样本内夏普排名）+ 样本外对比 + 全局相关系数 + 衰减分布</li><li>散点图（样本内 vs 样本外夏普，y=x 对角线虚线，Top 20 红色高亮）</li><li>Top 20 柱状图（每组双柱：样本内 / 样本外）</li><li>总结打印按实际数据动态描述：Top 20 平均衰减、对角线下方点的占比、过拟合定义</li></ol></blockquote><p>完整 spec 在 <a href="https://github.com/xingwudao/xquant-learning/blob/main/q6-avoid-overfitting/specs/spec-01-parameter-optimization.md" target="_blank" rel="noreferrer"><code>specs/spec-01-parameter-optimization.md</code></a>——复制给 AI，弹窗选「允许」。</p><p>AI 助手执行完毕后，你的 notebook 里应该出现了网格搜索的完整结果。我们来看看代码做了什么。</p><p>数据被切成了两段：<strong>样本内（In-Sample）</strong> 用 2017-2020 四年做优化，<strong>样本外（Out-of-Sample）</strong> 用 2021-2023 做验证。为什么选这么早的数据？因为样本内需要足够长（至少 3-4 年），才能覆盖牛熊周期，避免只在单一行情下调参。时间顺序也必须正确——先优化，后验证，就像真实投资中你只能用历史数据做决策，然后面对未来。</p><p><strong>样本内</strong>就是你看着答案复习的模拟考试卷；<strong>样本外</strong>就是真正的考试——你从没见过的题目。</p><p>四个维度的参数组合——动量窗口 5 种 × 波动率窗口 5 种 × 调仓频率 4 种 × 止损阈值（有/无），加上约束过滤（调仓频率不能超过信号窗口——用过期信息做决策没有意义），最终产生 490 种有效组合。</p><p><code>GridSearch</code> 把 490 种参数组合逐个跑回测，按夏普比排名。然后用同样的参数在样本外再跑一遍，看“真正的考试”成绩如何。</p><h3 id="运行结果" tabindex="-1">运行结果 <a class="header-anchor" href="#运行结果" aria-label="Permalink to &quot;运行结果&quot;">​</a></h3><p>490 种组合全部跑完，先看样本内 Top 20 的“样本外真相”——样本内夏普 Top 20 及其样本外表现（部分）如表 6-2 所示。</p><p><strong>表 6-2 样本内夏普 Top 20 及其样本外表现（部分）</strong></p><table tabindex="0"><thead><tr><th>#</th><th>mom</th><th>vol</th><th>freq</th><th>sl</th><th>样本内夏普</th><th>样本外夏普</th><th>衰减</th></tr></thead><tbody><tr><td>1</td><td>15</td><td>10</td><td>10</td><td>0.03</td><td>1.39</td><td>0.50</td><td>-0.88</td></tr><tr><td>2</td><td>15</td><td>15</td><td>10</td><td>0.03</td><td>1.34</td><td>0.49</td><td>-0.85</td></tr><tr><td>3</td><td>15</td><td>25</td><td>10</td><td>0.03</td><td>1.30</td><td>0.38</td><td>-0.92</td></tr><tr><td>4</td><td>15</td><td>20</td><td>10</td><td>0.03</td><td>1.29</td><td>0.39</td><td>-0.90</td></tr><tr><td>5</td><td>30</td><td>10</td><td>5</td><td>0.03</td><td>1.25</td><td>0.02</td><td>-1.23</td></tr><tr><td>7</td><td>30</td><td>10</td><td>10</td><td>0.03</td><td>1.24</td><td>-0.07</td><td>-1.31</td></tr><tr><td>14</td><td>15</td><td>10</td><td>10</td><td>无</td><td>1.18</td><td>0.01</td><td>-1.17</td></tr></tbody></table><p><strong>样本内 Top 20 统计：</strong> 样本内夏普均值 1.22（范围 1.15 ~ 1.39），样本外夏普均值 0.20（范围 -0.09 ~ 0.50），平均衰减 -1.02。</p><p><strong>全部 490 个组合统计：</strong> 样本内/样本外夏普相关系数 0.04，样本外比样本内差的比例 100%，夏普衰减均值 -0.82、中位数 -0.88。</p><p>散点图与 Top 20 柱状图如图 6-1 所示。</p><p><img src="'+a+'" alt="490 个参数组合：样本内 vs 样本外夏普比"></p><h3 id="结果解读" tabindex="-1">结果解读 <a class="header-anchor" href="#结果解读" aria-label="Permalink to &quot;结果解读&quot;">​</a></h3><p>第一个认知升级：<strong>参数优化是一把双刃剑。</strong></p><p>先看数字。样本内 Top 20 的平均夏普 1.22——这在量化里属于很拿得出手的成绩。但拿到样本外（2021-2023，没见过的数据），平均夏普跌到了 0.20。衰减了 83%。</p><p>再看散点图。每个点代表一种参数组合，对角虚线是“样本外 = 样本内”的理想状态。如果所有点都在对角线上，说明样本内的好成绩在样本外也能兑现。但现实是：<strong>100% 的点都在对角线以下</strong>——没有一种参数组合的样本外表现达到样本内水平。</p><p>更扎心的是：样本内夏普和样本外夏普的相关系数只有 0.04——几乎没有关系。样本内排名第一的组合，样本外并不一定最好。</p><p>这就是<strong>过拟合（Overfitting）</strong>——你的策略只会死读书，课后习题全都会做，结果高考考砸了。它“记住了”过去数据的特征（噪音），而不是发现了真正的规律。</p><p>柱状图更直观：蓝色柱子（样本内）高高在上，红色柱子（样本外）矮了一大截。有些组合样本外甚至为负——在“真正的考试”中亏了钱。</p><p><strong>数据说了算：参数优化后，必须在没见过的数据上验证。样本内的好成绩不算数。</strong></p><p><strong>这就是第一把铲子：样本内 / 样本外切分。</strong> 它不能直接帮你赚钱——但它能让你在第一时间看到“漂亮回测背后到底有没有真东西”。第一章那次“被自己骗”的肉身记忆，到这里第一次有了一件可以挂在墙上的工具。</p><p>怎么办？我们把数据切成了“优化”和“验证”两段，只验证了一次。但只验证一次够吗？市场在变，参数也该跟着变吧？</p><hr><h2 id="_6-2-市场在变-参数也该跟着变吧" tabindex="-1">6.2 市场在变，参数也该跟着变吧？ <a class="header-anchor" href="#_6-2-市场在变-参数也该跟着变吧" aria-label="Permalink to &quot;6.2 市场在变，参数也该跟着变吧？&quot;">​</a></h2><p>Step 1 把数据切成了“优化”和“验证”两段，发现了过拟合问题。但我们只切了一次、只验证了一次。</p><p>市场每年都在变。2020 年选的参数，2023 年还适用吗？能不能模拟“每隔一段时间重新优化参数”的过程？</p><p>直觉告诉我们：<strong>市场每年不一样，参数当然应该定期更新。</strong> 用最近的数据重新优化，应该比死守一组参数更好。</p><p>这个想法叫 <strong>Walk-forward（前推验证）分析</strong>——“边走边调”。在历史数据上模拟“每隔一段时间重新优化参数”的过程：用过去两年数据选参数，在接下来半年验证；然后窗口往前滑半年，再选参数、再验证……如此反复。</p><p>有两种滑动方式：</p><ul><li><strong>滚动式（Rolling）</strong>——固定数据窗口宽度，窗口左边位置不断往右移动。好处是只看最近的市场，坏处是丢弃了更早的数据。就像只翻最近两年的课本复习</li><li><strong>锚定式（Anchored）</strong>——固定数据窗口左边位置，窗口宽度不断拉长。好处是利用了所有历史数据，坏处是旧数据可能不再适用。就像从高一课本开始全部复习</li></ul><p>试试看——用两种不同的方式“边走边调”。</p><h3 id="动手实验-2-walk-forward-分析" tabindex="-1">动手实验 2：Walk-forward 分析 <a class="header-anchor" href="#动手实验-2-walk-forward-分析" aria-label="Permalink to &quot;动手实验 2：Walk-forward 分析&quot;">​</a></h3><p>我们一起把这份 spec 写出来。这次重点看两件新东西：<strong>循环型 spec 的端点全锁</strong>（窗口起止 + 长度 + 步长四个参数都不留浮动）、<strong>对照实验式 spec 的并列结构</strong>（让 Rolling / Anchored 自己跑出对比）。</p><h4 id="起草上下文-任务-1" tabindex="-1">起草上下文 + 任务 <a class="header-anchor" href="#起草上下文-任务-1" aria-label="Permalink to &quot;起草上下文 + 任务&quot;">​</a></h4><blockquote><p><strong>上下文</strong>：在 <code>q6-avoid-overfitting.ipynb</code> 中已有 490 个组合的网格搜索结果 + 样本内/样本外对比，过拟合现象已暴露。当前问题：数据只切了一次。市场在变，2023 年选的参数 2025 年还适用吗？能不能模拟“定期重新优化”的过程？</p><p><strong>任务</strong>：在 notebook 新建单元格，用 <code>oxq.optimize.WalkForward</code> 实现 Walk-forward 分析，对比 Rolling 和 Anchored 两种方式。</p></blockquote><h4 id="起草要求-循环窗口的四个端点" tabindex="-1">起草要求：循环窗口的四个端点 <a class="header-anchor" href="#起草要求-循环窗口的四个端点" aria-label="Permalink to &quot;起草要求：循环窗口的四个端点&quot;">​</a></h4><p>循环型 spec 比单次 spec 脆弱得多——单次 spec 漏掉一个日期可能没事，循环型 spec 漏掉就会让“折数”在不同时间跑出不同结果。</p><blockquote><p><strong>要求</strong>：</p><ol><li>复用 Step 1 的参数空间（无止损组 70 组合）和约束（<code>RebalanceFrequencyRule.interval_days &lt;= mom.period</code> / <code>&lt;= vol.period</code>）</li><li>数据范围：<code>DATA_START=&quot;2017-01-01&quot;</code> 到 <code>ANALYSIS_END=&quot;2026-05-06&quot;</code>——四个端点全锁死，不要用 <code>pd.Timestamp.now()</code></li><li>Rolling Walk-forward：训练窗口 <code>&quot;2Y&quot;</code>、测试窗口 <code>&quot;6M&quot;</code>、<code>anchored=False</code></li><li>Anchored Walk-forward：同上，<code>anchored=True</code>（训练窗口从起点不断扩大）</li><li><code>train_period=&quot;2Y&quot;</code> 的依据：覆盖一个完整中期周期；<code>test_period=&quot;6M&quot;</code> 的依据：足够长以观察策略表现，又足够短以让多个折落进数据范围</li></ol></blockquote><blockquote><p>📌 <strong>要点</strong>：循环型 spec 的窗口端点要四个全锁死——<strong>起始日 + 结束日 + 窗口长度 + 步长</strong>。漏掉任何一个，折数都会随时间漂移。如果用 <code>pd.Timestamp.now()</code> 当结束日，半年后跑出来折数从 15 变成 16，参数稳定性的结论可能就反过来了。<strong>任何带 <code>for</code> 循环的 spec 都要回头检查这四个端点。</strong></p></blockquote><blockquote><p>📌 <strong>要点</strong>：循环窗口的“为什么”也要写。<code>&quot;2Y&quot; / &quot;6M&quot;</code> 不是随手挑的——背后有“覆盖一个完整中期周期”和“折数 ≥ 5 才有统计意义”两个判断。<strong>领域知识里的窗口长度选择，跟参数选择本身一样重要——把判断写进 spec 注释，别让 AI 揣摩。</strong></p></blockquote><h4 id="起草结果呈现-1" tabindex="-1">起草结果呈现 <a class="header-anchor" href="#起草结果呈现-1" aria-label="Permalink to &quot;起草结果呈现&quot;">​</a></h4><blockquote><p><strong>结果呈现</strong>：</p><ol><li>用 <code>to_dataframe()</code> 打印每折详情：训练时段、验证时段、最优参数、样本内/样本外夏普</li><li>汇总：<code>oos_sharpe_ratio()</code>、<code>deterioration()</code>、各折参数集合</li><li>对比图（figsize 14×6，上下两栏）：上栏每折样本外夏普（Rolling 红 / Anchored 蓝两条线），下栏参数稳定性线图（mom.period / interval_days 各折取值）</li><li>标题「Walk-forward 分析：Rolling vs Anchored」</li><li>打印分析按实际数据动态描述：Anchored 是否锁定参数、Rolling 是否乱跳、衰减对比</li></ol></blockquote><p>完整 spec 在 <a href="https://github.com/xingwudao/xquant-learning/blob/main/q6-avoid-overfitting/specs/spec-02-walk-forward.md" target="_blank" rel="noreferrer"><code>specs/spec-02-walk-forward.md</code></a>——复制给 AI，弹窗选「允许」。</p><p>AI 助手执行完毕后，你的 notebook 里应该出现了 Rolling 和 Anchored 两种 Walk-forward 的完整结果。</p><p>训练窗口 2 年，验证窗口 6 个月。每次用 2 年数据选出最优参数，在接下来 6 个月验证。然后窗口滑动，重复这个过程。最终得到 15 折结果——15 次“选参数 → 验证”的记录。</p><h3 id="运行结果-1" tabindex="-1">运行结果 <a class="header-anchor" href="#运行结果-1" aria-label="Permalink to &quot;运行结果&quot;">​</a></h3><p>两种方式的对比如表 6-3 所示。</p><p><strong>表 6-3 Rolling vs Anchored 对比</strong></p><table tabindex="0"><thead><tr><th>方式</th><th>样本外夏普</th><th>衰减</th><th>唯一参数组合</th></tr></thead><tbody><tr><td>Rolling</td><td>0.14</td><td>-36.2%</td><td>7/15</td></tr><tr><td>Anchored</td><td>0.13</td><td>-23.5%</td><td>5/15</td></tr></tbody></table><p>Anchored 参数更稳定。</p><p>关键发现：Rolling 在 15 折（每次滑动算一折，一共滑了 15 次）中选了 7 种不同的参数组合——平均两折就换一种。而 Anchored 只有 5 种，且其中 7 折选了相同的参数（动量窗口 20、波动率窗口 15、调仓频率 5）——单一组合占了近一半折数。</p><p>Anchored 的逐折参数一览如表 6-4 所示。</p><p><strong>表 6-4 Anchored Walk-forward 逐折参数与样本外夏普</strong></p><table tabindex="0"><thead><tr><th>Fold</th><th>mom</th><th>vol</th><th>freq</th><th>样本外夏普</th></tr></thead><tbody><tr><td>1</td><td>15</td><td>15</td><td>5</td><td>2.50</td></tr><tr><td>2</td><td>15</td><td>15</td><td>5</td><td>0.71</td></tr><tr><td>3</td><td>20</td><td>15</td><td>5</td><td>-0.13</td></tr><tr><td>4</td><td>15</td><td>10</td><td>5</td><td>0.68</td></tr><tr><td>5</td><td>30</td><td>15</td><td>5</td><td>-2.49</td></tr><tr><td>6</td><td>20</td><td>15</td><td>5</td><td>-1.83</td></tr><tr><td>7</td><td>20</td><td>15</td><td>5</td><td>1.42</td></tr><tr><td>8</td><td>20</td><td>15</td><td>5</td><td>-0.67</td></tr><tr><td>9</td><td>20</td><td>15</td><td>5</td><td>1.91</td></tr><tr><td>10</td><td>20</td><td>15</td><td>5</td><td>-1.75</td></tr><tr><td>11</td><td>30</td><td>15</td><td>5</td><td>1.99</td></tr><tr><td>12</td><td>20</td><td>20</td><td>5</td><td>1.22</td></tr><tr><td>13</td><td>30</td><td>15</td><td>5</td><td>1.23</td></tr><tr><td>14</td><td>20</td><td>15</td><td>5</td><td>1.31</td></tr><tr><td>15</td><td>30</td><td>15</td><td>5</td><td>0.98</td></tr></tbody></table><p>（mom=20, vol=15, freq=5）这组参数前后出现了 7 次，是 Anchored 的最频繁选择。其余四种组合——（15, 15, 5）、（30, 15, 5）、（15, 10, 5）、（20, 20, 5）——各出现 1 到 4 次。换句话说：动量窗口在 15-30 之间换、波动率窗口大多停在 15、调仓频率 15 折全选 5。Rolling 的波动更宽——动量窗口在 15-30 之间跳、波动率窗口从 10 一直到 30，没有明确偏好。</p><p>每折样本外夏普走势与参数稳定性对比如图 6-2 所示。</p><p><img src="'+n+'" alt="Walk-forward 分析：Rolling vs Anchored"></p><h3 id="结果解读-1" tabindex="-1">结果解读 <a class="header-anchor" href="#结果解读-1" aria-label="Permalink to &quot;结果解读&quot;">​</a></h3><p>第二个认知升级：<strong>参数稳定性比参数最优更重要。</strong></p><p>先看上图。两条实线是样本外夏普——Rolling（红色）和 Anchored（蓝色）都有起伏，但起伏的方向大体一致。下图更关键：Rolling 的参数线在 mom=15-30、vol=10-30 间跳来跳去，Anchored 的两条线被压在更窄的区间内（mom 多在 20、vol 多在 15）。</p><p><strong>参数稳定性（Parameter Stability）</strong>——好的参数组合应该在不同时间窗口中保持一致。如果每换一个窗口参数就变，说明“最优参数”取决于你看哪段市场，这个参数可能只是在拟合噪音。</p><p>Anchored 在 15 折中 7 折都选了（mom=20, vol=15, freq=5）这一组——15 次里 7 次是同一个答案；剩下的折在四组里跳，但波动率窗口大多稳在 15、调仓频率 15 折全是 5。不管训练集从 2 年扩大到 9 年，参数选择都被限制在一个窄区间——这是一个好信号。而 Rolling 在 15 折里选出 7 种不同组合，每两折就换一次，说明它在追逐短期市场特征，而不是捕捉长期规律。</p><p>样本内到样本外的衰减比例：Rolling 衰减 36.2%，Anchored 衰减 23.5%。Anchored 衰减更小，因为它用了更多数据训练，不容易被噪音骗。</p><p>Walk-forward 的核心价值：不是找到一个“永远最优”的参数，而是检验你的优化方法在历史上是否靠谱。如果历史上每次优化后验证都不错，你对下一次优化会更有信心。</p><p><strong>数据说了算：参数稳定 = 更可信。如果最优参数总在变，你怎么知道现在选的参数下个月还是最优？</strong></p><p><strong>这就是第二把铲子：Walk-forward。</strong> 它把“换段时间还稳定吗”从一种焦虑变成了一项可以滚动跑的检查——参数稳定的策略你可以拿得动，参数到处变的策略你可以早早放弃。</p><p>但 Walk-forward 只用了一种切法——如果数据切的方式不同，结论还一致吗？</p><hr><h2 id="_6-3-一条路径够可靠吗" tabindex="-1">6.3 一条路径够可靠吗？ <a class="header-anchor" href="#_6-3-一条路径够可靠吗" aria-label="Permalink to &quot;6.3 一条路径够可靠吗？&quot;">​</a></h2><p>Walk-forward 模拟了“边走边调”，但我们只用了一种切法。如果换一种切数据的方式，结论还一样吗？</p><p>做科学实验有个基本原则：<strong>一次实验不够，要重复多次。</strong> 只做一次实验就下结论，可能只是碰巧。同样的道理——只验证一次（Step 1）或只用一种切法（Step 2）都不够可靠。</p><p>直觉告诉我们：<strong>好策略不管怎么切都好。</strong> 如果 5 次验证里 4 次都选了同样的参数，比只验证 1 次可信得多。</p><p>这就是<strong>交叉验证（Cross Validation）</strong>——用多种数据切分方式验证同一个策略，看结论是否一致。</p><p>但金融数据有一个特殊的限制，先用一个生活类比说清楚：<strong>做菜可以“先看明天的菜单再决定今天买什么菜”——但炒股不行</strong>，因为你今天根本不知道明天会发生什么。</p><p>把这个限制翻译成两个量化术语：</p><ul><li><strong>时间序列属性（Time-Series Nature）</strong> —— 金融数据有先后顺序：今天比昨天晚发生，比明天早发生。顺序不能打乱。</li><li><strong>时间穿越 / 数据泄露（Look-Ahead Bias / Data Leakage）</strong> —— 在训练或验证时，不小心让模型“看到了未来”。比如本应该用 2020 年的数据训练，结果你混了一点 2024 年的数据进来——这等于让你的策略在考试前“偷看了答案”，回测会异常漂亮，但放到实盘上一笔笔真金白银地亏。</li></ul><p>所以做交叉验证时<strong>每折必须保持时间顺序</strong>——这就是 <strong>时间序列分割（Time-Series Split）</strong>：训练集永远在测试集之前，绝不让“未来”出现在“过去”的训练里。</p><p>试试看。</p><h3 id="动手实验-3-交叉验证" tabindex="-1">动手实验 3：交叉验证 <a class="header-anchor" href="#动手实验-3-交叉验证" aria-label="Permalink to &quot;动手实验 3：交叉验证&quot;">​</a></h3><p>我们一起把这份 spec 写出来。这次重点看两件新东西：<strong>时序切分而非随机切分</strong>（金融数据的硬约束）、<strong>接续型 spec 的减法</strong>（不复述前面已经讲过的概念，专心做一件新事）。</p><h4 id="起草上下文-任务-2" tabindex="-1">起草上下文 + 任务 <a class="header-anchor" href="#起草上下文-任务-2" aria-label="Permalink to &quot;起草上下文 + 任务&quot;">​</a></h4><blockquote><p><strong>上下文</strong>：在 <code>q6-avoid-overfitting.ipynb</code> 中已有参数优化 + Walk-forward 分析。Walk-forward 只用了一种切法——如果换一种切法，结论还一样吗？一次验证和多次验证，可信度差多少？</p><p><strong>任务</strong>：在 notebook 新建单元格，用 <code>oxq.optimize.TimeSeriesCV</code> 实现时间序列交叉验证。</p></blockquote><h4 id="起草要求-时序切分的硬约束" tabindex="-1">起草要求：时序切分的硬约束 <a class="header-anchor" href="#起草要求-时序切分的硬约束" aria-label="Permalink to &quot;起草要求：时序切分的硬约束&quot;">​</a></h4><blockquote><p><strong>要求</strong>：</p><ol><li>复用 Step 2 的参数空间和约束（无止损组 70 组合）</li><li>数据范围：<code>DATA_START=&quot;2017-01-01&quot;</code> 到 <code>ANALYSIS_END=&quot;2026-05-06&quot;</code>——与 Step 2 同步锁死，保证 5 折切分点在任何时间跑都一致</li><li>用 <code>oxq.optimize.TimeSeriesCV</code>（不是 sklearn 的 <code>KFold</code>）：<code>n_splits=5</code>、<code>expanding=True</code></li><li>传入 <code>paramset</code>，让 <code>cross_validate()</code> 自动在每折训练集上做 GridSearch</li><li><code>n_splits=5</code> 的依据：ML 教科书默认值，7 年数据上每折约 1.4 年验证集，足够长</li><li><code>expanding=True</code> 的依据：训练集逐折扩大——Step 2 的 Anchored 比 Rolling 更稳定，本步跟随该结论</li></ol></blockquote><blockquote><p>📌 <strong>要点</strong>：金融数据要用时序切分，不能用随机切分。普通 ML 用 sklearn 的 <code>KFold</code> 是随机切的（可设 <code>random_state</code>）；金融场景必须用 <code>TimeSeriesSplit</code>——<strong>训练集永远在测试集之前，绝不让“未来”出现在“过去”的训练里</strong>。否则就是把答案偷给了考试中的你——回测看起来漂亮，实盘上一笔笔真金白银地亏，是这条硬约束最常见的代价。这是 q6 比通用 ML 课程多出的一条硬约束。</p></blockquote><blockquote><p>📌 <strong>要点</strong>：接续型 spec 应该做减法。spec-03 比 spec-01 / spec-02 都短得多——它不重新定义参数空间（直接复用 Step 2 的 <code>wf_paramset</code>）、不重讲一次什么是过拟合，专心做“5 折结果对比”一件事。<strong>承接型 spec 应当克制重复——前面 spec 讲过的就别再讲；只引入本 spec 真正新的东西。</strong></p></blockquote><h4 id="起草结果呈现-2" tabindex="-1">起草结果呈现 <a class="header-anchor" href="#起草结果呈现-2" aria-label="Permalink to &quot;起草结果呈现&quot;">​</a></h4><blockquote><p><strong>结果呈现</strong>：</p><ol><li>用 <code>cv_result.to_dataframe()</code> 打印汇总表，再 for 循环逐折打印（训练时段、验证时段、最优参数、样本内/样本外夏普、样本外收益）</li><li>汇总：<code>mean_oos_metric()</code> ± <code>std_oos_metric()</code> + 范围 [min, max] + 唯一参数组合数</li><li>柱状图（figsize 12×6）：每折样本内 / 样本外夏普双柱 + 样本外均值水平线</li><li>标题「5 折交叉验证：每折的样本内 vs 样本外夏普比」</li><li>打印分析按实际数据动态描述：5 折中几折选了相同参数、变异系数大小、与 Step 2 Anchored 结论是否一致</li></ol></blockquote><p>完整 spec 在 <a href="https://github.com/xingwudao/xquant-learning/blob/main/q6-avoid-overfitting/specs/spec-03-cross-validation.md" target="_blank" rel="noreferrer"><code>specs/spec-03-cross-validation.md</code></a>——复制给 AI，弹窗选「允许」。</p><p>AI 助手执行完毕后，你的 notebook 里应该出现了 5 折交叉验证的完整结果。</p><p><code>TimeSeriesCV</code> 把数据切成 5 折。每折用前面的数据训练（训练集逐渐扩大），紧跟着的一段做验证。每折都独立做网格搜索——选出该折的最优参数，再到验证集上检验。</p><h3 id="运行结果-2" tabindex="-1">运行结果 <a class="header-anchor" href="#运行结果-2" aria-label="Permalink to &quot;运行结果&quot;">​</a></h3><p>5 折交叉验证的逐折详情如表 6-5 所示。</p><p><strong>表 6-5 5 折交叉验证逐折详情</strong></p><table tabindex="0"><thead><tr><th>Fold</th><th>训练时段</th><th>验证时段</th><th>最优参数</th><th>样本内夏普</th><th>样本外夏普</th><th>样本外收益</th></tr></thead><tbody><tr><td>1</td><td>2017-01-01 ~ 2018-07-22</td><td>2018-07-23 ~ 2020-02-11</td><td>mom=15, vol=15, freq=5</td><td>0.87</td><td>0.69</td><td>14.37%</td></tr><tr><td>2</td><td>2017-01-01 ~ 2020-02-11</td><td>2020-02-12 ~ 2021-09-02</td><td>mom=15, vol=10, freq=5</td><td>0.72</td><td>0.44</td><td>10.82%</td></tr><tr><td>3</td><td>2017-01-01 ~ 2021-09-02</td><td>2021-09-03 ~ 2023-03-25</td><td>mom=20, vol=15, freq=5</td><td>0.66</td><td>0.28</td><td>4.33%</td></tr><tr><td>4</td><td>2017-01-01 ~ 2023-03-25</td><td>2023-03-26 ~ 2024-10-14</td><td>mom=20, vol=15, freq=5</td><td>0.53</td><td>1.56</td><td>37.83%</td></tr><tr><td>5</td><td>2017-01-01 ~ 2024-10-14</td><td>2024-10-15 ~ 2026-05-06</td><td>mom=20, vol=20, freq=5</td><td>0.72</td><td>1.79</td><td>67.22%</td></tr></tbody></table><p><strong>TopNRanking CV 汇总：</strong> 样本外夏普 0.95 ± 0.68，样本外范围 [0.28, 1.79]，唯一参数组合 4/5。</p><p>5 折中 Fold 3 与 Fold 4 选择了相同的参数（mom=20, vol=15, freq=5），其余三折各不相同——这组结果该怎么读？</p><p>每折样本内 vs 样本外夏普对比如图 6-3 所示。</p><p><img src="'+l+'" alt="5 折交叉验证：每折的样本内 vs 样本外夏普比"></p><h3 id="结果解读-2" tabindex="-1">结果解读 <a class="header-anchor" href="#结果解读-2" aria-label="Permalink to &quot;结果解读&quot;">​</a></h3><p>第三个认知升级：<strong>多次验证比单次验证更可靠。</strong></p><p>先看参数一致性。5 折里只有 Fold 3 和 Fold 4 选了同一组参数（mom=20, vol=15, freq=5），其余三折各不相同——单看 5 折，共识不算强。但有意思的是：这组（mom=20, vol=15, freq=5）也正是 Step 2 里 Anchored Walk-forward 在 15 折里出现 7 次的最频繁参数。两种独立的切法（一种 15 折滑动、一种 5 折时序切分）都把概率最高的位置指向了同一组参数——切法换了，结论没变。</p><p>再看表现波动。样本外夏普的范围从 0.28 到 1.79，标准差 0.68。变异系数（标准差/均值）约为 0.72，仍小于 1——说明样本外表现整体相对一致，但波动不容忽视：最好的折（1.79）比最差的折（0.28）高了 6 倍以上。参数对了不代表什么时候都有正收益——策略对市场环境仍然敏感。</p><p>交叉验证的价值不是给你一个“最优参数”，而是告诉你<strong>你的参数选择有多可靠</strong>。5 折下来如果共识强，可以更有信心；共识弱，就该接受“参数选择本身有不确定性”，而不是盯着某一折的结果。</p><p><strong>数据说了算：多次验证给出更立体的画像——共识强可以更进一步，共识弱就该承认不确定性。即使参数对了，也别期望每年都有正收益。</strong></p><p><strong>这就是第三把铲子：交叉验证。</strong> 它让你在多种切法下独立验证同一个结论——一次可能是巧合，多次都指向同一个答案就更可信。前两把铲子告诉你“是不是过拟合”，这一把告诉你“你有多大把握”。</p><p>到这里，我们从三个角度检验了参数选择——一次验证（Step 1）、动态验证（Step 2）、多次验证（Step 3）。但还有一种过拟合更隐蔽：不是参数选错了，而是<strong>规则太多了</strong>。</p><hr><h2 id="_6-4-规则越多回测越好——是好事吗" tabindex="-1">6.4 规则越多回测越好——是好事吗？ <a class="header-anchor" href="#_6-4-规则越多回测越好——是好事吗" aria-label="Permalink to &quot;6.4 规则越多回测越好——是好事吗？&quot;">​</a></h2><p>前三步检验的都是参数选择——找参数、更新参数、换切法验证参数。但还有一种过拟合更隐蔽。</p><p>回顾第四章：我们给策略加了止损、止盈、移动止损等交易规则。当时的结论是“不是所有规则都有用”。但那时我们没有做样本内/样本外验证。如果在样本内不断加规则、调参数，回测收益一路上升——这是真的在改进策略，还是只是在“凑”出好看的数字？</p><p>直觉告诉我们：<strong>规则越多保护越全面，效果应该越好。</strong> 止损防亏损、止盈锁利润、移动止损跟踪趋势——每一条都有道理。</p><p>真的吗？试试看——从最简单的策略开始，一层一层加规则，看样本内和样本外分别怎么变。</p><h3 id="动手实验-4-规则负担" tabindex="-1">动手实验 4：规则负担 <a class="header-anchor" href="#动手实验-4-规则负担" aria-label="Permalink to &quot;动手实验 4：规则负担&quot;">​</a></h3><p>我们一起把这份 spec 写出来。这次重点看两件新东西：<strong>规则数的定义</strong>（“规则数”和“自由度”是两个不同的轴）、<strong>业务约束链的金融语义</strong>（止损 &lt; 止盈 / 移动止损 ≥ 固定止损 / 回撤 ≥ 止损都是领域知识）。</p><h4 id="起草上下文-任务-3" tabindex="-1">起草上下文 + 任务 <a class="header-anchor" href="#起草上下文-任务-3" aria-label="Permalink to &quot;起草上下文 + 任务&quot;">​</a></h4><blockquote><p><strong>上下文</strong>：在 <code>q6-avoid-overfitting.ipynb</code> 中已有参数优化 + Walk-forward + 交叉验证。前三步检验“参数选得对不对”。本步检验另一种过拟合——规则太多。每加一条规则，就多了一个可调旋钮；旋钮越多，越容易在样本内“调出”好看的结果。</p><p><strong>任务</strong>：在 notebook 新建单元格，做两个堆叠实验展示规则负担。</p></blockquote><h4 id="起草要求-4a-规则堆叠-4b-自由度堆叠" tabindex="-1">起草要求：4A 规则堆叠 + 4B 自由度堆叠 <a class="header-anchor" href="#起草要求-4a-规则堆叠-4b-自由度堆叠" aria-label="Permalink to &quot;起草要求：4A 规则堆叠 + 4B 自由度堆叠&quot;">​</a></h4><p>把“加规则”和“加自由度”分两个实验跑，<strong>学员才能看出“是规则本身的问题还是自由度的问题”</strong>。</p><blockquote><p><strong>要求</strong>：</p><ol><li>编写 <code>run_layer(layer_name, rules, paramset, description)</code> 辅助函数，复用 Step 1 的样本内/外切分</li><li><strong>4A 规则堆叠</strong>（6 层）：基础策略 mom=20/vol=20/freq=10 固定，逐层添加交易规则 <ul><li>Layer 0：基础策略（无额外规则）</li><li>Layer 1：+ 优化调仓频率</li><li>Layer 2：+ 优化止损</li><li>Layer 3：+ 优化止盈（约束 sl &lt; tp）</li><li>Layer 4：+ 优化移动止损（约束 trail &gt;= sl）</li><li>Layer 5：+ 最大回撤风控（约束 max_dd &gt;= sl）</li></ul></li><li><strong>4B 自由度堆叠</strong>（5 配置）：从 1 自由度逐步加到 6 自由度 <ul><li>A：仅动量窗口（1 自由度）</li><li>B：+ 波动率（2）</li><li>C：+ 调仓频率（3）</li><li>D：+ 止损阈值（4）</li><li>E：+ 止盈 + 移动止损（6 自由度，粗网格 [10,20,30] 防止组合数爆炸）</li></ul></li><li>每层在样本内选最优 → 在样本外验证</li><li>约束链按金融语义编码：止损 &lt; 止盈、移动止损 ≥ 固定止损、回撤阈值 ≥ 止损</li></ol></blockquote><blockquote><p>📌 <strong>要点</strong>：q6 第一次显式区分“规则数”和“自由度”两个轴。<strong>4A 数的是“加了几条交易规则”</strong>（止损是一条规则，即便它只有一个 threshold 参数）；<strong>4B 数的是“有几个可优化的旋钮”</strong>（一条规则可能贡献 1 个或多个自由度）。两个轴不一样——通用 ML 课程很少这么分，但金融领域必须分：止损是一条独立的业务规则，它在 4A 里占一层；但它的 threshold 在 4B 里只贡献 1 自由度。<strong>学员看到两个实验的曲线分别走出 plateau 拐点，才能确认“既不是规则数的问题，也不是单纯自由度的问题，是两者都到了 plateau”。</strong></p></blockquote><blockquote><p>📌 <strong>要点</strong>：业务约束链要用金融语义，不是技术约束。<code>sl &lt; tp</code>（止损不能高于止盈，否则止损永远先触发）、<code>trail &gt;= sl</code>（移动止损不能比固定止损更严，否则后者无意义）、<code>max_dd &gt;= sl</code>（组合层风控阈值不应小于个仓止损，否则单仓止损还没触发组合就停了）——三组约束本身就是领域知识。<strong>spec 里的约束链 = 嵌入领域知识的标准位置；学员看 spec 学的不只是参数，还有“为什么这些参数之间该有先后关系”。</strong></p></blockquote><h4 id="起草结果呈现-3" tabindex="-1">起草结果呈现 <a class="header-anchor" href="#起草结果呈现-3" aria-label="Permalink to &quot;起草结果呈现&quot;">​</a></h4><blockquote><p><strong>结果呈现</strong>：</p><ol><li>两张汇总表：4A 六层 + 4B 五配置（含自由度、组合数、样本内/样本外夏普、衰减）</li><li>两张图（各 figsize 12×6，双折线）：4A「规则堆叠：样本内 vs 样本外」+ 4B「自由度越多 ≠ 越好」</li><li>打印分析按实际数据动态描述：4A 找出“超过这一层的规则都是规则负担”的最佳层、4B 找“自欺欺人开始”的拐点</li><li>引用 Brian Peterson 两段原话：「Rule burden is a form of overfitting」+「Too many rules will make a backtest look excellent in-sample, and may even work in walk forward analysis, but are very dangerous in production.」</li></ol></blockquote><p>完整 spec 在 <a href="https://github.com/xingwudao/xquant-learning/blob/main/q6-avoid-overfitting/specs/spec-04-rule-burden.md" target="_blank" rel="noreferrer"><code>specs/spec-04-rule-burden.md</code></a>——复制给 AI，弹窗选「允许」。</p><p>AI 助手执行完毕后，你的 notebook 里应该出现了两组实验的完整结果。</p><p><strong>4A：逐层添加规则。</strong> 从最简单的基础策略出发，每层多加一条规则，每层都在样本内做优化。约束条件先把不合理的组合（比如止损大于止盈、移动止损小于固定止损）过滤掉——剩下的层差异才不会被荒谬组合污染。</p><p><strong>4B：逐步增加参数维度。</strong> 从只调 1 个参数（动量窗口）开始，逐步增加可调参数的数量。<strong>自由度（Degrees of Freedom）</strong>——可以调节的参数和规则的数量。自由度越多，优化器的“调节空间”就越大。</p><h3 id="运行结果-3" tabindex="-1">运行结果 <a class="header-anchor" href="#运行结果-3" aria-label="Permalink to &quot;运行结果&quot;">​</a></h3><p>4A 规则堆叠的样本内/样本外表现如表 6-6 所示。</p><p><strong>表 6-6 4A 规则堆叠：每层规则的样本内/样本外夏普与衰减</strong></p><table tabindex="0"><thead><tr><th>Layer</th><th>描述</th><th>组合数</th><th>样本内夏普</th><th>样本外夏普</th><th>衰减</th></tr></thead><tbody><tr><td>0</td><td>基础（固定参数）</td><td>1</td><td>0.94</td><td>0.52</td><td>-0.43</td></tr><tr><td>1</td><td>+ 优化调仓频率</td><td>3</td><td>1.06</td><td>-0.07</td><td>-1.13</td></tr><tr><td>2</td><td>+ 优化止损</td><td>18</td><td>1.11</td><td>0.36</td><td>-0.75</td></tr><tr><td>3</td><td>+ 优化止盈</td><td>57</td><td>1.33</td><td>0.15</td><td>-1.18</td></tr><tr><td>4</td><td>+ 优化移动止损</td><td>183</td><td>1.33</td><td>0.15</td><td>-1.18</td></tr><tr><td>5</td><td>+ 最大回撤风控</td><td>825</td><td>1.33</td><td>0.15</td><td>-1.18</td></tr></tbody></table><p>4B 指标堆叠（按可优化的自由度分档）的对比如表 6-7 所示。</p><p><strong>表 6-7 4B 指标堆叠：自由度递增下的样本内/样本外夏普</strong></p><table tabindex="0"><thead><tr><th>配置</th><th>自由度</th><th>组合数</th><th>描述</th><th>样本内夏普</th><th>样本外夏普</th><th>衰减</th></tr></thead><tbody><tr><td>A</td><td>1</td><td>5</td><td>动量窗口</td><td>1.07</td><td>-0.17</td><td>-1.24</td></tr><tr><td>B</td><td>2</td><td>25</td><td>+ 波动率窗口</td><td>1.18</td><td>0.01</td><td>-1.17</td></tr><tr><td>C</td><td>3</td><td>70</td><td>+ 调仓频率</td><td>1.18</td><td>0.01</td><td>-1.17</td></tr><tr><td>D</td><td>4</td><td>420</td><td>+ 止损阈值</td><td>1.39</td><td>0.50</td><td>-0.88</td></tr><tr><td>E</td><td>6</td><td>323</td><td>+ 止盈 + 移动止损</td><td>1.56</td><td>-0.07</td><td>-1.62</td></tr></tbody></table><p>随层数 / 自由度增加，样本内一路向上、样本外却平甚至下降，对比如图 6-4 所示。</p><p><img src="'+s+'" alt="4A 规则堆叠 与 4B 自由度越多不等于越好"></p><h3 id="结果解读-3" tabindex="-1">结果解读 <a class="header-anchor" href="#结果解读-3" aria-label="Permalink to &quot;结果解读&quot;">​</a></h3><p>第四个认知升级：<strong>规则越多 != 策略越好，简单就是美。</strong></p><p>这是本章最重要的认知冲击。</p><p>先看 4A。样本内夏普从 Layer 0 的 0.94 爬升到 Layer 3 的 1.33——每加一条规则，优化器都能在样本内找到更好看的结果。但样本外呢？Layer 0 （基础策略，完全没有额外规则）的样本外夏普是 0.52——这是所有层中最高的！加了调仓频率优化后（Layer 1），样本外直接变成了 -0.07。止损（Layer 2）挽回了一些（0.36），但之后的止盈、移动止损、回撤风控全部无效——样本外停在 0.15 不再提升。</p><p>注意 Layer 3-5 三行的样本内、样本外、衰减数字一字不差（IS 1.33 / OS 0.15 / 衰减 -1.18）——这不是抄错。Layer 3 引入了 <code>sl &lt; tp</code>、Layer 4 又叠 <code>trail &gt;= sl</code>、Layer 5 再叠 <code>max_dd &gt;= sl</code>，三条约束把搜索空间一层层锁死。再增加的旋钮被前面的约束吃掉，最后什么都调不动。<strong>这是规则负担的另一面：旋钮多了，相互之间的约束也多，优化器其实根本没机会真正“利用”那几个新自由度。</strong></p><p>也就是说：最简单的基础策略，反而是样本外表现最好的。</p><p>再看 4B。从配置 D 到配置 E，自由度从 4 增加到 6，样本内夏普从 1.39 升到 1.56（好了 12%），但样本外从 0.50 跌到 -0.07——<strong>自欺欺人的拐点</strong>出现了。多出来的两个参数让优化器在样本内找到了更好看的结果，但在样本外完全不兑现。</p><p>为什么会这样？每条新规则都增加一个<strong>自由度</strong>——可以调节的旋钮。旋钮越多，优化器就有越多的空间去“凑”出好看的回测结果。这不是在发现真规律，而是在记忆噪音。这就是<strong>规则负担（Rule Burden）</strong>——规则本身就是一种过拟合的来源。规则太多会让回测看起来很漂亮，甚至在前推验证中也可能过关，但放到实盘就很危险。</p><p>这个判断不是我们一拍脑袋——R 语言量化框架 quantstrat 的作者 Brian Peterson 早就说过：“规则负担本身就是一种过拟合（Rule burden is a form of overfitting）。规则太多会让回测在样本内异常漂亮，甚至在前推验证里也能过关，但放到实盘就非常危险。”每条规则都是给优化器多一个旋钮——旋钮越多，凑出好看回测的余地就越大，对真实未来的把握反而越小。</p><p><strong>铁律：能用 2 个参数解决的问题，不要用 6 个。每增加一条规则，都要问——样本外也改善了吗？如果没有，删掉它。少即是多。</strong></p><p><strong>这就是第四把铲子：规则负担。</strong> 它告诉你少即是多——不是“加规则越多策略越好”，而是“每加一条规则都要在样本外验证它真的帮上忙”。这把铲子和前三把不同：前三把帮你检查已有的策略，这一把帮你<strong>在设计阶段就少挖坑</strong>。</p><hr><h2 id="_6-5-回头看-你刚才做了什么" tabindex="-1">6.5 回头看：你刚才做了什么？ <a class="header-anchor" href="#_6-5-回头看-你刚才做了什么" aria-label="Permalink to &quot;6.5 回头看：你刚才做了什么？&quot;">​</a></h2><p><strong>6.5 是“做”——四把铲子的操作流程总图，把四步实验铺成你以后每次接到一份回测都能照着走的检查路径。</strong> 四步下来，我们从四个角度回答了同一个核心问题——“这个参数组合是真的好，还是运气好？”</p><ul><li><strong>Step 1: 参数优化</strong> → 490 种组合，样本内很好 → 样本外全面衰减 → 过拟合</li><li><strong>Step 2: Walk-forward</strong> → 模拟“边走边调” → 参数稳定才可信</li><li><strong>Step 3: 交叉验证</strong> → 5 折独立验证 → 共识强可以更进一步，共识弱就该承认不确定性</li><li><strong>Step 4: 规则负担</strong> → 规则越多样本内越好 → 样本外不买账 → 简单就是美</li></ul><p>从今以后，拿到任何策略的回测结果，可以用一套防过拟合检查清单核对一遍真实性，如表 6-8 所示。</p><p><strong>表 6-8 防过拟合检查清单</strong></p><table tabindex="0"><thead><tr><th>检查项</th><th>怎么做</th><th>好的信号</th><th>坏的信号</th></tr></thead><tbody><tr><td>样本外验证</td><td>在没见过的数据上跑</td><td>衰减小</td><td>衰减大</td></tr><tr><td>Walk-forward</td><td>分窗口优化+验证</td><td>参数跨窗口稳定</td><td>参数每次都变</td></tr><tr><td>交叉验证</td><td>多折验证</td><td>各折结果一致</td><td>各折差异巨大</td></tr><tr><td>规则负担</td><td>从简到繁，逐层加</td><td>样本外同步改善</td><td>样本内改善但样本外不变</td></tr><tr><td>参数敏感性（第五章）</td><td>扫描参数</td><td>高原型</td><td>山峰型</td></tr></tbody></table><p>加上第五章的参数敏感性，你手上已经有五把检验策略的武器。第一章那次“被自己的回测骗”的肉身记忆，到这里被沉淀成了一份可以挂在墙上的检查清单——这就是“疑”从感觉变成方法的过程，也是飞轮归因层在你手里第一次完整闭环的一小步。下次再接到一份“漂亮”的回测，你不会再赤手空拳，而是知道该问哪几个问题、用哪几把铲子去挖。</p><p>更重要的是：这四把铲子不只是让你“能识破自己的过拟合”，它们也让你<strong>敢于做更激进的策略实验</strong>——因为你知道有工具可以兜住底。怀疑回测不是为了畏手畏脚，是为了能放心动手。这就是“疑”和“做”在飞轮里的真正关系：<strong>疑得越深，做得越敢。</strong></p><hr><h2 id="_6-6-本章总结" tabindex="-1">6.6 本章总结 <a class="header-anchor" href="#_6-6-本章总结" aria-label="Permalink to &quot;6.6 本章总结&quot;">​</a></h2><p><strong>6.6 是“概念速查 + 带走的问题”——和 6.5 严格分工：6.5 写“怎么做”，6.6 写“用到了什么 / 还有什么没回答”。</strong></p><h3 id="策略进化路径" tabindex="-1">策略进化路径 <a class="header-anchor" href="#策略进化路径" aria-label="Permalink to &quot;策略进化路径&quot;">​</a></h3><p>第五章产出：完整的策略评估方法论 + 体检清单 → Step 1: 参数优化（样本内很好但样本外衰减，过拟合） → Step 2: Walk-forward（模拟定期重新优化，参数稳定性） → Step 3: 交叉验证（多次验证更可靠，但表现差异大） → Step 4: 规则负担（规则/参数越多越危险，简单就是美） → 第六章产出：四把防身工具 + 防过拟合检查清单 + “怀疑回测”的态度</p><h3 id="概念速查表" tabindex="-1">概念速查表 <a class="header-anchor" href="#概念速查表" aria-label="Permalink to &quot;概念速查表&quot;">​</a></h3><p>本章涉及的核心概念汇总如表 6-9 所示，方便随时回查。</p><p><strong>表 6-9 第六章核心概念速查</strong></p><table tabindex="0"><thead><tr><th>概念</th><th>含义</th><th>类比</th></tr></thead><tbody><tr><td>参数优化 / 网格搜索</td><td>把所有可能的参数组合都试一遍，选出表现最好的</td><td>从几千所大学里挑分数最高的</td></tr><tr><td>样本内（训练集）</td><td>用来优化参数的那段数据</td><td>模拟考试的试题</td></tr><tr><td>样本外（测试集）</td><td>用来验证参数的另一段数据，优化时没见过</td><td>真正的考试</td></tr><tr><td>过拟合</td><td>样本内表现很好但样本外大幅衰减</td><td>背了真题成绩好，但没学会真知识</td></tr><tr><td>Walk-forward 分析</td><td>在历史上模拟“定期重新优化”的过程</td><td>每学期重新选课本复习</td></tr><tr><td>滚动式 Walk-forward</td><td>训练窗口固定大小，向前滑动</td><td>只翻最近两年的课本</td></tr><tr><td>锚定式 Walk-forward</td><td>训练窗口从起点开始，越来越大</td><td>从高一课本开始全部复习</td></tr><tr><td>参数稳定性</td><td>好参数在不同窗口中保持一致</td><td>不管怎么考，你的强项科目都一样</td></tr><tr><td>交叉验证</td><td>用多种切法验证同一个策略</td><td>做实验要重复多次才可信</td></tr><tr><td>时间序列分割</td><td>保持时间顺序的交叉验证</td><td>不能用未来考题“复习”过去</td></tr><tr><td>规则负担</td><td>每条新规则增加过拟合风险</td><td>考试作弊手段越多，被抓的风险越大</td></tr><tr><td>自由度</td><td>可以调节的参数和规则数量</td><td>作弊的旋钮越多，越容易凑出高分</td></tr></tbody></table><h3 id="本章核心认知" tabindex="-1">本章核心认知 <a class="header-anchor" href="#本章核心认知" aria-label="Permalink to &quot;本章核心认知&quot;">​</a></h3><p>走完四步实验后，本章最值得带走的八条认知如表 6-10 所示。</p><p><strong>表 6-10 第六章核心认知</strong></p><table tabindex="0"><thead><tr><th>认知</th><th>来源</th></tr></thead><tbody><tr><td>参数优化是双刃剑——优化后必须在新数据上验证</td><td>Step 1</td></tr><tr><td>样本内的好成绩不算数</td><td>Step 1</td></tr><tr><td>参数稳定性比参数最优更重要</td><td>Step 2</td></tr><tr><td>好参数跨窗口稳定，坏参数到处变</td><td>Step 2</td></tr><tr><td>多次验证比单次验证更可靠</td><td>Step 3</td></tr><tr><td>不同验证方法指向同一个参数 → 可信度高</td><td>Step 3</td></tr><tr><td>规则越多 != 策略越好</td><td>Step 4</td></tr><tr><td>能用 2 个参数解决的问题，不要用 6 个</td><td>Step 4</td></tr></tbody></table><h3 id="带走的问题" tabindex="-1">带走的问题 <a class="header-anchor" href="#带走的问题" aria-label="Permalink to &quot;带走的问题&quot;">​</a></h3><p>我们已经知道怎么评估策略（第五章）、怎么防过拟合（第六章）。回测世界的问题基本解决了。</p><p>但回测终究是模拟。在回测里，你可以按任何价格、在任何时间成交。真实世界里呢？</p><ul><li>你想买的时候，市场上有足够的卖盘吗？</li><li>你下单到成交之间，价格会不会已经变了？</li><li>回测假设的手续费，和真实交易一样吗？</li></ul><p><strong>从回测到实盘，还有多少坑在等着你？</strong> → 第七章</p><p><strong>你在第一章撞过那堵墙，第五章手里有了体检表，这一章把怀疑变成了肌肉记忆。下面一章，回测的世界要让位给真实成交的世界——你将带着这四把铲子，走进实盘。</strong></p><blockquote><p>本章所有代码的可运行版本见 <code>notebooks/q6-avoid-overfitting.ipynb</code></p></blockquote><hr><h2 id="反馈与读者群" tabindex="-1">反馈与读者群 <a class="header-anchor" href="#反馈与读者群" aria-label="Permalink to &quot;反馈与读者群&quot;">​</a></h2><p>如果你发现本章有错别字、概念不清或实验结果不一致，欢迎 <a href="https://github.com/xingwudao/xquant-beginner/issues/new/choose" target="_blank" rel="noreferrer">提交 GitHub Issue</a>。</p><p>课程、正式书和后续更新见 <a href="https://xquant.shop/courses" target="_blank" rel="noreferrer">xquant.shop/courses</a>。</p><p>添加作者微信 <code>xquanter</code> 进入读者群。请备注：<code>XQuant 读者</code>。</p>',218)]))}const k=d(p,[["render",i]]);export{m as __pageData,k as default};
